SELECT T1.product_id
FROM reviews AS T1
WHERE T1.sentiment_score > (SELECT AVG(sentiment_score) FROM reviews);

SELECT COUNT(DISTINCT r.product_id) AS product_count
FROM reviews r
WHERE r.review_text LIKE '%awesome%';

SELECT AVG(average_rating)
FROM products
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Baby Products');
